  sed -i 's/^AI_TUTOR_NEET_PHYSICS_DB_COURSE_ID=.*/AI_TUTOR_NEET_PHYSICS_DB_COURSE_ID=138/' /opt/robodynamics/ai-tutor/tutor-api/.env || true
  sed -i 's/^AI_TUTOR_NEET_CHEMISTRY_DB_COURSE_ID=.*/AI_TUTOR_NEET_CHEMISTRY_DB_COURSE_ID=131/' /opt/robodynamics/ai-tutor/tutor-api/.env || true
  sed -i 's/^AI_TUTOR_NEET_BIOLOGY_DB_COURSE_ID=.*/AI_TUTOR_NEET_BIOLOGY_DB_COURSE_ID=132/' /opt/robodynamics/ai-tutor/tutor-api/.env || true
  grep -q '^AI_TUTOR_TEMPLATE_COURSE_IDS=' /opt/robodynamics/ai-tutor/tutor-api/.env && sed -i 's#^AI_TUTOR_TEMPLATE_COURSE_IDS=.*#AI_TUTOR_TEMPLATE_COURSE_IDS=neet_physics:138,neet_chemistry:131,neet_biology:132#' /opt/robodynamics/ai-tutor/tutor-api/.env || echo 'AI_TUTOR_TEMPLATE_COURSE_IDS=neet_physics:138,neet_chemistry:131,neet_biology:132' >> /opt/robodynamics/ai-tutor/tutor-api/.env
fi

FILE=/opt/tomcat/bin/setenv.sh
mkdir -p /opt/tomcat/bin
[ -f "$FILE" ] || touch "$FILE"
sed -i '/# BEGIN RD_AI_TUTOR_NEET_IDS/,/# END RD_AI_TUTOR_NEET_IDS/d' "$FILE"
cat >> "$FILE" <<'BLOCK'
# BEGIN RD_AI_TUTOR_NEET_IDS
CATALINA_OPTS="${CATALINA_OPTS:-} -Drd.ai.tutor.neet.physics.db-course-id=138 -Drd.ai.tutor.neet.chemistry.db-course-id=131 -Drd.ai.tutor.neet.biology.db-course-id=132"
export CATALINA_OPTS
# END RD_AI_TUTOR_NEET_IDS
BLOCK

if systemctl list-unit-files | awk '{print $1}' | grep -q '^tomcat9\.service$'; then TOMSVC=tomcat9; else TOMSVC=tomcat; fi
systemctl restart "$TOMSVC"
cd /opt/robodynamics/ai-tutor/web
npm run build >/tmp/rd_ai_tutor_web_build.log 2>&1 || (tail -n 120 /tmp/rd_ai_tutor_web_build.log; exit 1)
systemctl restart rd-ai-tutor-api
systemctl restart rd-ai-tutor-web
sleep 2
echo "TOMCAT=$(systemctl is-active $TOMSVC || true)"
echo "API=$(systemctl is-active rd-ai-tutor-api || true)"
echo "WEB=$(systemctl is-active rd-ai-tutor-web || true)"

KEY=$(grep -E '^TUTOR_INTERNAL_KEY=' /opt/robodynamics/ai-tutor/tutor-api/.env | head -n1 | cut -d= -f2-)
for cid in neet_physics neet_chemistry neet_biology; do
  echo "=== catalog $cid ==="
  curl -s -H "X-AI-TUTOR-KEY: $KEY" "http://127.0.0.1:8091/ai-tutor-api/tutor/catalog?courseId=$cid" | python3 -c 'import sys,json; d=json.load(sys.stdin); ch=d.get("chapters") or []; print("resolved=",d.get("courseId"),"chapters=",len(ch)); print("first=", (ch[0].get("title") if ch else ""))'
done
